import React, { useState, useEffect, useCallback } from 'react';
import { Radar, ShieldAlert, Newspaper, Share2, Info } from 'lucide-react';
import { AIRFIELDS } from './constants';
import { Theme } from './types';
import { AirfieldCard } from './components/AirfieldCard';
import { KyivClock } from './components/KyivClock';
import { ThemeToggle } from './components/ThemeToggle';
import { getTacticalBriefing } from './services/geminiService';

const App: React.FC = () => {
  const [theme, setTheme] = useState<Theme>('dark');
  const [markedAirfields, setMarkedAirfields] = useState<Set<string>>(new Set());
  const [briefing, setBriefing] = useState<string>("Завантаження тактичного брифінгу...");
  const [isLoadingBriefing, setIsLoadingBriefing] = useState(false);

  // Toggle theme
  const toggleTheme = () => {
    const newTheme = theme === 'dark' ? 'light' : 'dark';
    setTheme(newTheme);
    document.documentElement.classList.toggle('dark', newTheme === 'dark');
  };

  // Toggle airfield status
  const handleToggleMarked = (id: string) => {
    setMarkedAirfields(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  };

  // Fetch AI Briefing when active airfields change
  const updateBriefing = useCallback(async () => {
    setIsLoadingBriefing(true);
    const activeNames = AIRFIELDS
      .filter(a => markedAirfields.has(a.id))
      .map(a => a.name);

    const text = await getTacticalBriefing(activeNames);
    setBriefing(text || "Не вдалося завантажити дані.");
    setIsLoadingBriefing(false);
  }, [markedAirfields]);

  useEffect(() => {
    updateBriefing();
  }, [markedAirfields, updateBriefing]);

  return (
    <div className="min-h-screen pb-20 selection:bg-blue-500 selection:text-white transition-colors duration-500">
      {/* HEADER */}
      <header className="sticky top-0 z-50 bg-white/80 dark:bg-sky-dark/80 backdrop-blur-md border-b border-slate-200 dark:border-slate-800">
        <div className="max-w-7xl mx-auto px-4 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-500/30">
              <Radar className="w-6 h-6 animate-pulse" />
            </div>
            <div>
              <h1 className="text-xl font-extrabold tracking-tight dark:text-white">SkyTrack<span className="text-blue-600">Ua</span></h1>
              <p className="text-[10px] uppercase tracking-widest font-bold text-slate-500">Tactical Monitoring</p>
            </div>
          </div>

          <div className="flex items-center gap-4 md:gap-8">
            <KyivClock />
            <ThemeToggle theme={theme} onToggle={toggleTheme} />
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 mt-8 space-y-8">
        {/* TACTICAL BRIEFING (AI SECTION) */}
        <section className="bg-blue-50 dark:bg-blue-900/10 border border-blue-200 dark:border-blue-800/50 rounded-3xl p-6 md:p-8 flex flex-col md:flex-row gap-6 items-start">
          <div className="w-12 h-12 bg-blue-100 dark:bg-blue-900/30 rounded-2xl flex items-center justify-center flex-shrink-0">
            <Newspaper className="w-6 h-6 text-blue-600 dark:text-blue-400" />
          </div>
          <div className="flex-1">
            <div className="flex items-center gap-2 mb-2">
              <h2 className="font-bold text-blue-900 dark:text-blue-300 uppercase tracking-wide text-sm">Штучний Інтелект: Тактичний Брифінг</h2>
              {isLoadingBriefing && <div className="w-2 h-2 bg-blue-500 rounded-full animate-ping" />}
            </div>
            <p className="text-slate-700 dark:text-slate-300 leading-relaxed font-medium">
              {briefing}
            </p>
          </div>
          <button 
            onClick={updateBriefing}
            className="text-xs font-bold text-blue-600 dark:text-blue-400 hover:underline flex items-center gap-1"
          >
            Оновити аналіз
          </button>
        </section>

        {/* MONITORING GRID */}
        <div className="space-y-6">
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
            <div>
              <div className="flex items-center gap-2 mb-1">
                <ShieldAlert className="w-5 h-5 text-shahed-red" />
                <h2 className="text-2xl font-black dark:text-white uppercase">Аеродроми Пуску</h2>
              </div>
              <p className="text-slate-500 dark:text-slate-400 text-sm">Оберіть локації, з яких зафіксовано вихід БПЛА для оповіщення спільноти.</p>
            </div>

            <div className="flex items-center gap-2 px-4 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl">
               <span className="text-xs font-bold text-slate-500 uppercase">Активних точок:</span>
               <span className="px-2 py-0.5 rounded-md bg-shahed-red/20 text-shahed-red font-bold text-sm">
                 {markedAirfields.size}
               </span>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {AIRFIELDS.map((airfield) => (
              <AirfieldCard 
                key={airfield.id}
                airfield={airfield}
                isMarked={markedAirfields.has(airfield.id)}
                onToggle={handleToggleMarked}
              />
            ))}
          </div>
        </div>

        {/* INFO FOOTER SECTION */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-12 pt-8 border-t border-slate-200 dark:border-slate-800">
          <div className="p-6 bg-slate-100 dark:bg-sky-card rounded-2xl flex gap-4">
            <div className="w-10 h-10 bg-slate-200 dark:bg-slate-800 rounded-xl flex items-center justify-center flex-shrink-0">
              <Info className="w-5 h-5 text-slate-500" />
            </div>
            <div>
              <h4 className="font-bold dark:text-white mb-1">Про SkyTrackUa</h4>
              <p className="text-sm text-slate-500 dark:text-slate-400">Система швидкого реагування та візуалізації загроз. Дані базуються на OSINT-дослідженнях та офіційних звітах.</p>
            </div>
          </div>

          <div className="p-6 bg-slate-100 dark:bg-sky-card rounded-2xl flex gap-4">
            <div className="w-10 h-10 bg-slate-200 dark:bg-slate-800 rounded-xl flex items-center justify-center flex-shrink-0">
              <Share2 className="w-5 h-5 text-slate-500" />
            </div>
            <div>
              <h4 className="font-bold dark:text-white mb-1">Поділитися</h4>
              <p className="text-sm text-slate-500 dark:text-slate-400">Допоможіть розповсюдити сервіс для підвищення обізнаності населення під час атак.</p>
            </div>
          </div>
        </div>
      </main>

      <footer className="mt-20 py-10 text-center border-t border-slate-200 dark:border-slate-800">
        <p className="text-sm text-slate-500 font-medium">© 2024 SkyTrackUa Monitoring Team. Разом до перемоги.</p>
      </footer>
    </div>
  );
};

export default App;

