              <p className="text-[10px] uppercase tracking-widest font-bold text-slate-500">Tactical Monitoring</p>
            </div>
          </div>

          <div className="flex items-center gap-4 md:gap-8">
            <KyivClock />
            <ThemeToggle theme={theme} onToggle={toggleTheme} />
          </div>
