import { ThemeToggle } from './components/ThemeToggle';
import { getTacticalBriefing, getHistoricalAnalysis } from './services/geminiService';

const App: React.FC = () => {
  const [theme, setTheme] = useState<Theme>('dark');
  const [markedAirfields, setMarkedAirfields] = useState<Set<string>>(new Set());
  const [briefing, setBriefing] = useState<string>("Завантаження тактичного брифінгу...");
  const [statsAnalysis, setStatsAnalysis] = useState<string>("Аналізуємо дані...");
  const [isLoadingBriefing, setIsLoadingBriefing] = useState(false);

  const toggleTheme = () => {
    const newTheme = theme === 'dark' ? 'light' : 'dark';
    setTheme(newTheme);
    document.documentElement.classList.toggle('dark', newTheme === 'dark');
  };

  const handleToggleMarked = (id: string) => {
    setMarkedAirfields(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  };

  const clearAllMarkers = () => {
    setMarkedAirfields(new Set());
  };

  const updateAiData = useCallback(async () => {
    setIsLoadingBriefing(true);
    const activeNames = AIRFIELDS
      .filter(a => markedAirfields.has(a.id))
      .map(a => a.name);

    const [briefingText, analysisText] = await Promise.all([
      getTacticalBriefing(activeNames),
      getHistoricalAnalysis()
    ]);

    setBriefing(briefingText || "Дані уточнюються.");
    setStatsAnalysis(analysisText || "Дані уточнюються.");
    setIsLoadingBriefing(false);
  }, [markedAirfields]);

  useEffect(() => {
    updateAiData();
  }, [markedAirfields, updateAiData]);

  // Analytics Chart Component (SVG)
  const SimpleBarChart = () => (
    <div className="w-full h-64 flex items-end justify-between gap-2 px-4 pb-8 border-b border-slate-200 dark:border-slate-800">
      {HISTORICAL_STATS.map((stat, idx) => {
        const heightLaunches = (stat.launches / 3000) * 100;
        const heightIntercepted = (stat.intercepted / 3000) * 100;
        return (
          <div key={idx} className="flex-1 flex flex-col items-center group relative h-full justify-end">
            <div className="w-full flex justify-center gap-1 items-end h-full">
              <div 
                className="w-1/3 bg-blue-500/30 dark:bg-blue-500/20 rounded-t-sm transition-all duration-500 group-hover:bg-blue-500/50"
                style={{ height: `${heightLaunches}%` }}
              />
              <div 
                className="w-1/3 bg-emerald-500 rounded-t-sm transition-all duration-700 group-hover:scale-y-105 origin-bottom"
                style={{ height: `${heightIntercepted}%` }}
              />
            </div>
            <span className="absolute -bottom-6 text-[10px] font-bold text-slate-500 uppercase tracking-tighter truncate w-full text-center">
              {stat.month.substring(0, 3)}
            </span>
            {/* Tooltip */}
            <div className="absolute bottom-full mb-2 hidden group-hover:block bg-slate-900 text-white p-2 rounded text-[10px] z-10 whitespace-nowrap shadow-xl">
              Пусків: {stat.launches}<br/>
              Збито: {stat.intercepted}
            </div>
          </div>
        );
      })}
    </div>
  );

  return (
    <div className="min-h-screen pb-20 selection:bg-blue-500 selection:text-white transition-colors duration-500 bg-slate-50 dark:bg-sky-dark text-slate-900 dark:text-slate-100">
      {/* HEADER */}
      <header className="sticky top-0 z-50 bg-white/80 dark:bg-sky-dark/80 backdrop-blur-md border-b border-slate-200 dark:border-slate-800">
        <div className="max-w-7xl mx-auto px-4 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-500/30">
              <Radar className="w-6 h-6 animate-pulse" />
            </div>
            <div>
              <h1 className="text-xl font-extrabold tracking-tight">SkyTrack<span className="text-blue-600">Ua</span></h1>
              <p className="text-[10px] uppercase tracking-widest font-bold text-slate-500">Monitoring & Analysis</p>
            </div>
          </div>

          <div className="flex items-center gap-4 md:gap-8">
            <KyivClock />
            <ThemeToggle theme={theme} onToggle={toggleTheme} />
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 mt-8 space-y-12">
        {/* TOP METRICS (ACCURACY FOCUS) */}
        <section className="grid grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="bg-white dark:bg-sky-card p-4 rounded-2xl border border-slate-200 dark:border-slate-800">
            <div className="flex items-center justify-between mb-2">
              <Database className="w-4 h-4 text-slate-400" />
              <span className="text-[10px] font-black text-blue-500 uppercase">Верифіковано</span>
            </div>
            <p className="text-xs font-bold text-slate-500 uppercase">Всього БПЛА (2024)</p>
            <p className="text-2xl font-black">{GLOBAL_SUMMARY.total2024.toLocaleString()}</p>
          </div>
          <div className="bg-white dark:bg-sky-card p-4 rounded-2xl border border-slate-200 dark:border-slate-800">
            <div className="flex items-center justify-between mb-2">
              <ShieldCheck className="w-4 h-4 text-emerald-500" />
              <ArrowUpRight className="w-4 h-4 text-emerald-500" />
            </div>
            <p className="text-xs font-bold text-slate-500 uppercase">Ефективність ППО</p>
            <p className="text-2xl font-black text-emerald-500">{GLOBAL_SUMMARY.averageInterception}%</p>
          </div>
          <div className="bg-white dark:bg-sky-card p-4 rounded-2xl border border-slate-200 dark:border-slate-800">
            <div className="flex items-center justify-between mb-2">
              <Clock className="w-4 h-4 text-slate-400" />
              <span className="text-[10px] font-black text-amber-500 uppercase">Пік активності</span>
            </div>
            <p className="text-xs font-bold text-slate-500 uppercase">Найважчий місяць</p>
            <p className="text-xl font-black">{GLOBAL_SUMMARY.mostActiveMonth}</p>
          </div>
          <div className="bg-white dark:bg-sky-card p-4 rounded-2xl border border-slate-200 dark:border-slate-800">
            <div className="flex items-center justify-between mb-2">
              <TrendingUp className="w-4 h-4 text-blue-500" />
            </div>
            <p className="text-xs font-bold text-slate-500 uppercase">Річна динаміка</p>
            <p className="text-2xl font-black text-blue-500">{GLOBAL_SUMMARY.trend}</p>
          </div>
        </section>

        {/* TACTICAL BRIEFING */}
        <section className="bg-blue-50 dark:bg-blue-900/10 border border-blue-200 dark:border-blue-800/50 rounded-3xl p-6 md:p-8 flex flex-col md:flex-row gap-6 items-start">
          <div className="w-12 h-12 bg-blue-100 dark:bg-blue-900/30 rounded-2xl flex items-center justify-center flex-shrink-0">
            <Newspaper className="w-6 h-6 text-blue-600 dark:text-blue-400" />
          </div>
          <div className="flex-1">
            <div className="flex items-center gap-2 mb-2">
              <h2 className="font-bold text-blue-900 dark:text-blue-300 uppercase tracking-wide text-sm">AI Тактичний Аналіз Поточної Ситуації</h2>
              {isLoadingBriefing && <div className="w-2 h-2 bg-blue-500 rounded-full animate-ping" />}
