import React, { useState, useEffect, useCallback } from 'react';
import { 
  Radar, ShieldAlert, Newspaper, Share2, Info, 
  BarChart3, Map as MapIcon, TrendingUp, Target, 
  ShieldCheck, Trash2, LayoutDashboard, Database,
  ArrowUpRight, Clock, X, AlertCircle, CheckCircle, RotateCcw,
  Zap
} from 'lucide-react';
import { AIRFIELDS, INITIAL_HISTORICAL_STATS, LAUNCH_DISTRIBUTION, GLOBAL_SUMMARY, StatEntry } from './constants';
import { Theme } from './types';
import { AirfieldCard } from './components/AirfieldCard';
import { KyivClock } from './components/KyivClock';
import { ThemeToggle } from './components/ThemeToggle';
import { getTacticalBriefing, getHistoricalAnalysis } from './services/geminiService';

const App: React.FC = () => {
  const [theme, setTheme] = useState<Theme>('dark');
  const [markedAirfields, setMarkedAirfields] = useState<Set<string>>(new Set());
  const [isBallisticThreat, setIsBallisticThreat] = useState(false);
  const [briefing, setBriefing] = useState<string>("Завантаження тактичного аналізу...");
  const [statsAnalysis, setStatsAnalysis] = useState<string>("Синхронізація з базою даних...");
  const [isLoadingBriefing, setIsLoadingBriefing] = useState(false);
  const [historicalStats, setHistoricalStats] = useState<StatEntry[]>(INITIAL_HISTORICAL_STATS);
  const [showBriefing, setShowBriefing] = useState(true);

  const toggleTheme = () => {
    const newTheme = theme === 'dark' ? 'light' : 'dark';
    setTheme(newTheme);
    document.documentElement.classList.toggle('dark', newTheme === 'dark');
  };

  const handleToggleMarked = (id: string) => {
    setMarkedAirfields(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  };

  const clearAllMarkers = () => {
    setMarkedAirfields(new Set());
    setIsBallisticThreat(false);
  };

  const deleteStatEntry = (id: string) => {
    setHistoricalStats(prev => prev.filter(entry => entry.id !== id));
  };

  const resetStats = () => {
    setHistoricalStats(INITIAL_HISTORICAL_STATS);
  };

  const updateAiData = useCallback(async () => {
    setIsLoadingBriefing(true);
    const activeNames = AIRFIELDS
      .filter(a => markedAirfields.has(a.id))
      .map(a => a.name);

    if (isBallisticThreat) activeNames.push("Загроза БАЛІСТИКИ");

    const [briefingText, analysisText] = await Promise.all([
      getTacticalBriefing(activeNames),
      getHistoricalAnalysis()
    ]);

    setBriefing(briefingText || "Дані уточнюються...");
    setStatsAnalysis(analysisText || "Дані уточнюються...");
    setIsLoadingBriefing(false);
  }, [markedAirfields, isBallisticThreat]);

  useEffect(() => {
    updateAiData();
  }, [markedAirfields, isBallisticThreat, updateAiData]);

  const AnalyticsChart = () => (
    <div className="w-full">
      <div className="w-full h-80 flex items-end justify-between gap-3 px-4 pb-12 border-b border-slate-200 dark:border-slate-800 relative group/chart">
        {historicalStats.length === 0 ? (
          <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-400">
            <Database className="w-12 h-12 mb-2 opacity-20" />
            <p className="text-sm font-black uppercase tracking-widest mb-4">Статистику видалено</p>
            <button 
              onClick={resetStats}
              className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-xl font-bold text-xs uppercase tracking-wider hover:bg-blue-700 transition-colors shadow-lg shadow-blue-600/20"
            >
              <RotateCcw className="w-4 h-4" />
              Відновити точні дані
            </button>
          </div>
        ) : (
          historicalStats.map((stat) => {
            const heightLaunches = (stat.launches / 3000) * 100;
            const heightIntercepted = (stat.intercepted / 3000) * 100;
            return (
              <div key={stat.id} className="flex-1 flex flex-col items-center group relative h-full justify-end">
                <button 
                  onClick={() => deleteStatEntry(stat.id)}
                  className="absolute top-0 opacity-0 group-hover:opacity-100 transition-all p-1.5 bg-red-500 hover:bg-red-600 text-white rounded-full z-20 shadow-xl transform -translate-y-2 group-hover:translate-y-0"
                  title="Видалити цей місяць"
                >
                  <Trash2 className="w-3.5 h-3.5" />
                </button>

                <div className="w-full flex justify-center gap-1.5 items-end h-full relative">
                  <div 
                    className="w-1/2 bg-blue-500/20 dark:bg-blue-500/10 border-x border-t border-blue-500/30 rounded-t-lg transition-all duration-700"
                    style={{ height: `${heightLaunches}%` }}
                  />
                  <div 
