                </div>

                <div className="absolute -bottom-8 w-full text-center">
                  <span className="text-[10px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-tighter block truncate px-1">
                    {stat.month}
                  </span>
                </div>
              </div>
            );
          })
        )}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen pb-20 selection:bg-blue-600 selection:text-white transition-colors duration-500 bg-slate-50 dark:bg-sky-dark text-slate-900 dark:text-slate-100 font-sans relative">
